"""
mkt-original: Zechariah ch1-7 — comprehensive Hebrew philological commentary (98 verses).
Covers the eight night visions (chs 1-6) and the fasting questions (ch 7).
Run: python3 scripts/zc-original-zechariah-1-7.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}


def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=2))
    print(f'  wrote {p.relative_to(ROOT)}')


def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, text in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = text


DATA = {
    "1": {
        "1": "<p><strong>davar YHWH el Zekharyahu ben Berekhyahu ben Iddoh hanavi</strong>: 'The word of the LORD came to Zechariah son of Berechiah son of Iddo the prophet.' The name <em>Zekharyahu</em> (H2148) means 'YHWH remembers' (<em>zakhar</em> = to remember, H2142). The remembrance-name is programmatic for the book: the book's entire message is that YHWH has not forgotten his people or his covenant promises, despite the desolation of Jerusalem and the temple. His grandfather Iddo (H5714) appears in the list of returning priests and Levites (Neh 12:4, 16), confirming the priestly family context. Zechariah is both prophet and priest — a combination important for his vision of the messianic priest-king (ch. 6).</p>",
        "2": "<p><strong>qetsaf YHWH al avoteikhem qetzef gadol</strong>: 'The LORD was very angry with your fathers.' The oracle opens with a striking acknowledgment: YHWH's <em>qetsaf gadol</em> (great wrath/anger, H7110) toward the fathers explains the exile. This is the prophetic diagnosis that forms the ground for the call to repentance in v3: the exile was not a defeat of YHWH but an expression of his justified wrath. The fathers are contrasted with the present generation: the call is to not repeat what the fathers did. The opening frames the restoration oracles that follow within the context of honest acknowledgment of why the exile happened.</p>",
        "3": "<p><strong>shuvu elai neum YHWH tzvaot va'ashuv aleikhem</strong>: 'Return to me, declares the LORD of hosts, and I will return to you.' The call-response formula of repentance — <em>shuvu ... va'ashuv</em> (return ... and I will return) — is the OT's most concentrated statement of covenant restoration theology. The same root <em>shuv</em> (H7725, to turn, return, repent) used for human return and divine return: both movements use the same word, implying that the divine 'return' (removal of judgment) is the corollary of human return (repentance). This formula appears also in Mal 3:7 (Return to me, and I will return to you). The NT's prodigal son narrative (Luke 15:20: while he was still a long way off, his father ran to him) dramatizes the same divine-response pattern.</p>",
        "4": "<p><strong>al tihyu ka'avoteikhem asher qar'u aleihem hanevi'im harishonim laimor shuvu na midarkeikhemha ra'im umima'alileikhemha hara'im</strong>: 'Do not be like your fathers, to whom the former prophets cried out: Thus declares the LORD of hosts, Return from your evil ways and from your evil deeds.' The 'former prophets' (<em>hanevi'im harishonim</em>) are the pre-exilic classical prophets (Isaiah, Jeremiah, Amos, Hosea, Micah, etc.) whose message of repentance the fathers rejected — leading to the exile. Zechariah locates himself in the prophetic succession and calls the current generation to learn from their predecessors' failure. 'They did not hear, and they did not pay attention to me, declares the LORD' — the failure of prophetic preaching to move the previous generation is the cautionary background.</p>",
        "5": "<p><strong>avoteikhem eyeh vehanevi'im hale'olam yichyu</strong>: 'Your fathers, where are they? And the prophets, do they live forever?' The rhetorical questions press the transience of both the generation that rejected YHWH's word and the prophets who brought it. The question 'where are they?' implies: they are gone, in the grave — but the word they rejected remains. This is the OT's version of 1 Pet 1:24-25: 'All flesh is like grass... but the word of the LORD remains forever.' The permanence of YHWH's word outlasts the generations that receive or reject it.</p>",
        "6": "<p><strong>akh devarai vechuqqai asher tziviti et avadai hanevi'im halo higshu avoteikhem vayashuvu vayomru ka'asher zamam YHWH tzvaot la'asot lanu kiderakhenu uvema'alaleinu ken asah itanu</strong>: 'But my words and my statutes, which I commanded my servants the prophets, did they not overtake your fathers?' The word <em>higshu</em> (from H5381, to reach, overtake) — the divine word is like a pursuer that eventually catches up: YHWH's threatened judgments did overtake the fathers who ignored the prophets. The fathers' eventual acknowledgment ('as the LORD of hosts purposed to do to us... so he has dealt with us') is repentance after the fact — too late to avoid the exile but the foundation for the current generation's different response.</p>",
        "7": "<p><strong>beesor vearba'ah livadash hasheni bishnat shtayim leDaryavesh</strong>: 'On the twenty-fourth day of the eleventh month, which is the month of Shebat, in the second year of Darius.' The date formula (February 519 BCE) is precise: Zechariah's visions came three months after Haggai's first oracle (Hag 1:1, August/September 520 BCE) and during the period of temple rebuilding. The historicity markers (regnal year of Darius, month name Shebat) ground the visions in concrete historical circumstances. The eight night visions that follow (vv8-21 and continuing through ch6) are received in a single night — a sustained visionary experience.</p>",
        "8": "<p><strong>ra'iti balayla vehineh ish rochev al sus adom vehu omed bein hahadassim asher bameitzulah</strong>: 'I saw in the night, and behold, a man riding on a red horse! He was standing among the myrtle trees in the glen.' The first vision: the divine rider among the myrtle trees. <em>Hadassim</em> (myrtle trees, H1918) — the same root as Hadassah, Esther's Hebrew name. Myrtle was associated with blessing and restoration in prophetic literature (Isa 41:19; 55:13: instead of the brier the myrtle shall come up). The 'glen' or ravine (<em>meitzulah</em>, H4699 — depth, deep place) may represent the low valley of Israel's humiliation. The rider on the red horse is later identified as the Angel of the LORD (v11) — a divine figure.</p>",
        "9": "<p><strong>vaomar mah eleh Adonai vayomer elai hamalakh haddover bi ani areka mah eleh</strong>: 'Then I said, What are these, O Lord? The angel who talked with me said to me, I will show you what these are.' The interpretive angel (<em>hamalakh haddover bi</em>, the angel who spoke with/in me) is a characteristic feature of Zechariah's visions — an angelic guide who interprets the symbolic content, similar to Daniel (Dan 7:16; 8:16) and later the apocalyptic tradition. The 'I will show you' structure introduces the explanatory dialogue that follows: vision, followed by dialogue, followed by interpretation. This is the standard structure for Zechariah's eight night visions.</p>",
        "10": "<p><strong>vaya'an ha'ish ha'omed bein hahadassim vayomar eleh asher shalach YHWH lehithalek ba'aretz</strong>: 'And the man standing among the myrtle trees answered and said, These are they whom the LORD has sent to patrol the earth.' The patrol riders (<em>shalach ... lehithalek</em> = sent to walk about) are divine agents monitoring the state of the earth. The intelligence they return (v11: the earth is at rest) creates the problem: the nations are prospering while Jerusalem lies desolate. The divine patrol discovers that the settled condition of the nations is itself evidence of YHWH's continued anger — comfortable nations, suffering Jerusalem.</p>",
        "11": "<p><strong>vaya'anu et malakh YHWH ha'omed bein hahadassim vayomru hithalaknu ba'aretz vehineh kol ha'aretz yoshevet ushaqatat</strong>: 'And they answered the angel of the LORD who was standing among the myrtle trees, We have patrolled the earth, and behold, all the earth remains at rest and quiet.' The patrol's report: <em>kol ha'aretz yoshevet ushaqatat</em> (all the earth sitting and quiet). The world's peace and stability — good in general — is here the ground for prophetic complaint: why should the nations be at peace while Jerusalem lies in ruins? The divine warrior's wrath against the nations (vv14-15) flows from this discrepancy.</p>",
        "12": "<p><strong>vaya'an malakh YHWH vayomar YHWH tzvaot ad matai ata lo terachhem et Yerushalayim ve'et arei Yehudah asher za'amta zeh shivim shanah</strong>: 'Then the angel of the LORD said: O LORD of hosts, how long will you have no mercy on Jerusalem and the cities of Judah, against which you have been angry these seventy years?' The Angel of the LORD intercedes — he prays to YHWH. This is theologically significant: a divine figure intercedes with YHWH for YHWH's people. The seventy years (<em>shivim shanah</em>) echoes Jeremiah's prophecy (Jer 25:11-12; 29:10) — the period of Babylonian domination. The intercessory prayer 'how long?' (<em>ad matai</em>) is the lament prayer of the Psalms (Ps 13:1; 79:5; 89:46) placed on the lips of the heavenly intercessor.</p>",
        "13": "<p><strong>vaya'an YHWH et hamalakh haddover bi devarim tovim devarim nichmuim</strong>: 'And the LORD answered gracious and comforting words to the angel who talked with me.' YHWH responds to the Angel's intercession with <em>devarim tovim devarim nichmuim</em> (good words, comforting/consoling words — H5150 from <em>nacham</em> = to comfort, console). These 'comforting words' are the substance of the following oracles: zeal for Jerusalem (v14), anger against the nations (v15), return to Jerusalem with mercies (v16), the measuring line (v16), overflow of prosperity (v17). The intercessory pattern: the Angel prays; YHWH responds; Zechariah announces. The NT parallel: Christ's heavenly intercession (Heb 7:25) produces divine comfort for his people.</p>",
        "14": "<p><strong>vayomer elai hamalakh haddover bi qera leimor koh amar YHWH tzvaot qinneti liYerushalayim uleTziyon qinah gedolah</strong>: 'So the angel who talked with me said to me, Cry out: Thus says the LORD of hosts: I am exceedingly jealous for Jerusalem and for Zion.' <em>Qinneti ... qinah gedolah</em> (I am jealous with great jealousy) — the doubled root for emphasis. YHWH's jealousy (<em>qinah</em>, H7068 — zeal, jealousy, passionate attachment) for Jerusalem is the emotional ground of the restoration: he is not indifferent to his city's desolation but passionately committed to its restoration. The same attribute that made him angry at Israel's idolatry (Exod 20:5: I am a jealous God) now makes him angry at the nations' complacency about Jerusalem's suffering.</p>",
        "15": "<p><strong>veqetzef gadol ani qotzef al hagoyim hashanannim</strong>: 'I am exceedingly angry with the nations that are at ease.' The nations' ease (<em>sha'anannim</em>, H7600 — complacent, at ease, arrogant) is their sin: they were YHWH's instruments of discipline against Israel, but they exceeded their mandate and became complacent about Israel's suffering. 'I was a little angry, and they furthered the disaster' — the nations interpreted Israel's punishment as license to inflict more. This is a significant theological point: divine instruments of judgment are themselves judged for their excess and complacency. The Babylonian empire's fall (612-539 BCE) was precisely this judgment against the instrument that exceeded its mandate.</p>",
        "16": "<p><strong>lachen koh amar YHWH shavti liYerushalayim berachamim beiti yibbaneh bah neum YHWH tzvaot veqav yinnateh al Yerushalayim</strong>: 'Therefore, thus says the LORD: I have returned to Jerusalem with mercy; my house shall be built in it, declares the LORD of hosts, and the measuring line shall be stretched over Jerusalem.' YHWH's return (<em>shavti</em>, from <em>shuv</em> — the same return-verb of v3) to Jerusalem is the first specific restoration promise. The measuring line (<em>qav</em>, H6957 — the builder's/surveyor's line) stretched over Jerusalem means the city will be rebuilt — not destroyed as in Lam 2:8 (the LORD stretched out the measuring line, purpose: to destroy). The image is reversed: the line that once marked out for destruction now marks out for construction.</p>",
        "17": "<p><strong>od qera leimor koh amar YHWH tzvaot od tifutzeynah arai mittov venichum YHWH od et Tziyon uvchar od biYerushalayim</strong>: 'Cry out again: Thus says the LORD of hosts: My cities shall again overflow with prosperity, and the LORD will again comfort Zion and again choose Jerusalem.' The triple <em>od</em> (again, still, yet) creates insistence: again prosperity, again comfort (<em>nichum</em>, from <em>nacham</em> = to console), again election (<em>bachar</em> = to choose). The theology of divine re-choice: the exile did not cancel the election of Jerusalem; YHWH 'again chooses' Jerusalem signals the permanence of covenant election that runs through temporary judgment (cf. Rom 11:29: the gifts and calling of God are irrevocable).</p>",
        "18": "<p><strong>vaessa et einai vaere vehineh arba qaranot</strong>: 'And I lifted my eyes and saw, and behold, four horns!' The second vision: four horns and four craftsmen (vv18-21). <em>Qaranot</em> (horns, H7161) are symbols of power throughout the OT (Deut 33:17; Ps 75:4-5; Dan 7:7-8, 24; Rev 13:1). The angel identifies them as the nations/powers that scattered Judah, Israel, and Jerusalem (v19). Four is the number of compass directions — these are world-powers from all directions. The craftsmen (<em>charashim</em>, H2796) come to terrify them and cast down the nations that lifted their horns against the land of Judah.</p>",
        "19": "<p><strong>vayomer elai eleh haqeranot asher zeru et Yehudah et Yisrael veYerushalayim</strong>: 'And he said to me, These are the horns that have scattered Judah, Israel, and Jerusalem.' The four scattering powers are not identified (Assyria, Babylon, Persia, Greece are the standard candidates) — the vision deliberately uses the number four to represent comprehensive, directional oppression. The verb <em>zeru</em> (from <em>zarah</em>, H2219 — to scatter, winnow) echoes the exile: Israel was scattered like grain on the threshing floor. The four craftsmen come to terrify these horns — the powers of scattering will themselves be overwhelmed.</p>",
        "20": "<p><strong>vayar'eni YHWH arba charashim</strong>: 'Then the LORD showed me four craftsmen/smiths.' <em>Charashim</em> (H2796 — craftsmen, smiths, carvers) — those who work with metal or wood. Four craftsmen against four horns: divine workmanship against world-power. The image may draw on the ancient Near Eastern combat myth (divine craftsman defeats chaos) recast in terms of YHWH's historical actions through human agents. The craftsmen represent the successive world powers (Persia against Babylon, Greece against Persia, etc.) that YHWH uses to overthrow Israel's oppressors.</p>",
        "21": "<p><strong>vayomer eleh ba'u leyarid et qaranot hagoyim hamerim qarnah el eretz Yehudah lezarotah</strong>: 'He said, These have come to terrify them, to cast down the horns of the nations who lifted up their horns against the land of Judah to scatter it.' The purpose of the craftsmen: to cast down (<em>yadot</em>, H3034 — to throw, cast down) the horns/powers of the scattering nations. The four-horns/four-craftsmen vision establishes that YHWH's sovereign control over history includes both the judgment that scatters Israel and the counter-judgment that overthrows those instruments of scattering. No world power — Assyrian, Babylonian, Persian, Greek — stands beyond YHWH's ultimate governance.</p>"
    },
    "2": {
        "1": "<p><strong>vaessa et einai vaere vehineh ish uveyadoh chevel middah</strong>: 'And I lifted my eyes and saw, and behold, a man with a measuring line in his hand!' The third vision: the man with the measuring line (ch2 in Hebrew versification; note that English ch2 = Hebrew ch2:1-13). The measuring line (<em>chevel middah</em>, H4060) is the surveyor's tool for planning construction. The man is going to measure Jerusalem — prepare for building. This contrasts with Lam 2:8 (YHWH stretched the line to destroy): now the line signals restoration, not destruction.</p>",
        "2": "<p><strong>vaomar ana ata holekh vayomer elai lmad et Yerushalayim lir'ot mah rachbah umah arkah</strong>: 'And I said, Where are you going? And he said to me, To measure Jerusalem, to see what is its width and what is its length.' The city survey for future building. The fact that Jerusalem will be measured implies it will be rebuilt — and the following oracles (vv4-5) reveal that the rebuilt Jerusalem will be so large it cannot be walled: a city without walls, because YHWH himself will be its wall of fire.</p>",
        "3": "<p><strong>vehineh hamalakh haddover bi yotze umalakh acher yotze liqrato</strong>: 'And behold, the angel who talked with me came forward, and another angel came forward to meet him.' Two angels — the interpretive angel and another — engage in dialogue. The second angel brings urgent information: the measuring is interrupted by a message too important to wait. The structure creates expectation: the normal procedure (measuring, survey) is suspended because YHWH has a word to speak about Jerusalem's future that transcends normal building plans.</p>",
        "4": "<p><strong>vayomer elav rutz daber el hana'ar hallaz leimor perazot teishev Yerushalayim merov adam uvehemah betokhah</strong>: 'And said to him, Run, say to that young man: Jerusalem shall be inhabited as villages without walls, because of the multitude of people and livestock in it.' <em>Perazot</em> (H6519 — open towns, unwalled villages) — not the embarrassment of an undefended city but the blessing of a population so large it cannot be contained within any wall. 'Villages without walls' is a prosperity image: settled, peaceful farming communities that have no need of defensive walls because YHWH is the defense. The multitude of people and livestock echoes the patriarchal blessing promises.</p>",
        "5": "<p><strong>va'ani ehyeh lah neum YHWH chomatei esh saviv ulechavod ehyeh betokhah</strong>: 'And I will be to her a wall of fire all around, declares the LORD, and I will be the glory in her midst.' Two divine promises: (1) <em>chomatei esh</em> (wall of fire) — YHWH himself as the city's protection, beyond any physical fortification. Fire-as-divine-presence echoes the pillar of fire in the wilderness (Exod 13:21-22; 14:24). (2) <em>leckhavod ehyeh betokhah</em> (I will be the glory in her midst) — the Shekinah restored. The glory that departed from Jerusalem before the exile (Ezek 10-11) will return. The two promises together — external protection and internal divine presence — describe the eschatological city.</p>",
        "6": "<p><strong>hoi hoi venusu me'eretz tzafon neum YHWH ki ke'arba ruchot hashamayim pirastiy etchem neum YHWH</strong>: 'Up! Up! Flee from the land of the north, declares the LORD. For I have spread you abroad as the four winds of the heavens, declares the LORD.' The urgent call to flee Babylon (<em>eretz tzafon</em>, the land of the north — Babylon is north of Israel by geography of travel) is addressed to the exiles who have not yet returned. YHWH scattered them (<em>pirastiy</em>, from H6566 = to spread, scatter) as the four winds scatter — now the reverse: they should gather themselves and flee back to the land.</p>",
        "7": "<p><strong>hoi Tziyon himaletiy yoshevet bat Bavel</strong>: 'Up! Escape to Zion, you who dwell with the daughter of Babylon.' The second call to flee: 'daughter of Babylon' (<em>bat Bavel</em>) personifies the Babylonian empire as a city/woman. Those dwelling comfortably in Babylon's prosperity (its economic benefits for Jewish exiles are attested in the Murashu documents from Nippur) are called to choose Zion over Babylon. The NT parallel: Rev 18:4 ('Come out of her, my people') uses the same exodus-from-Babylon imagery for eschatological departure from worldly systems opposed to God.</p>",
        "8": "<p><strong>ki koh amar YHWH tzvaot achar kavod shelachani el hagoyim hashollim etchem ki hannogea bakhem noge'a bevavat eino</strong>: 'For thus said the LORD of hosts, after his glory sent me to the nations who plundered you, for he who touches you touches the apple of his eye.' The phrase <em>bavat eino</em> (the apple/pupil of his eye, H892) — the most sensitive and vulnerable part of the eye, used metaphorically for that which YHWH most carefully guards. Israel/Jerusalem is the apple of YHWH's eye: to touch them is to touch YHWH himself at his most sensitive point. The motif of divine protection through radical identification with his people is the ground for the following judgment on the nations.</p>",
        "9": "<p><strong>ki hineni menif et yadi aleihem vehayu shalal le'avdeihem vedatem ki YHWH tzvaot shelachani</strong>: 'Behold, I will shake my hand over them, and they shall become plunder for those who served them. Then you will know that the LORD of hosts has sent me.' The divine hand shaken over the oppressor-nations (the same gesture used for judgment in Isa 11:15; 19:16) will reverse the power dynamic: the plundered become plunderers; the servants of the nations become their masters. 'You will know that YHWH of hosts sent me' — this authenticating phrase is said by the divine messenger who is both sent by YHWH and himself divine (the Angel of the LORD), anticipating the NT's Sent One Christology.</p>",
        "10": "<p><strong>roni veSimchi bat Tziyon ki hineni ba veshakhanti betokhech neum YHWH</strong>: 'Sing and rejoice, O daughter of Zion, for behold, I am coming and I will dwell in your midst, declares the LORD.' The call to joy (<em>roni veSimchi</em> — the same verbs as Zeph 3:14) is grounded in YHWH's promise to dwell (<em>shakhanti</em>, from <em>shakhan</em> = to tabernacle/dwell, H7931) in Jerusalem's midst. <em>Shakhan</em> is the root of the Hebrew <em>Shekhinah</em> — the divine indwelling presence. The NT's most direct application: John 1:14 (the Word became flesh and tabernacled/dwelt among us, using the Greek <em>eskēnōsen</em> which translates <em>shakhan</em>). YHWH's coming to dwell is the incarnation.</p>",
        "11": "<p><strong>venil'vu goyim rabbim el YHWH bayom hahu vehayu li le'am veshakhanti vetokhech veyada'at ki YHWH tzvaot shelachani elayich</strong>: 'And many nations shall join themselves to the LORD in that day, and shall be my people. And I will dwell in your midst, and you shall know that the LORD of hosts has sent me to you.' The joining of nations (<em>venil'vu goyim rabbim</em>, from <em>lavah</em> = to join, H3867) to YHWH — becoming his people — is the eschatological expansion of the covenant community beyond ethnic Israel. 'Shall be my people' (<em>vehayu li le'am</em>) is covenant adoption language: the covenant formula ('I will be your God and you shall be my people') extended to Gentile nations. Paul's theology of Gentile inclusion (Rom 9:24-26; Eph 2:11-22) develops this vision.</p>",
        "12": "<p><strong>venachal YHWH et Yehudah chelqo al admat haqodesh uvacher od biYerushalayim</strong>: 'And the LORD will inherit Judah as his portion in the holy land, and will again choose Jerusalem.' The theological claim is striking: YHWH 'inherits' (<em>nachal</em>, H5157 — to inherit, possess as a heritage) Judah as his portion. The usual direction of inheritance is from God to people (Ps 16:5: YHWH is my portion and my cup), but here the direction reverses: YHWH inherits his people and land as his own treasured possession. The holy land (<em>admat haqodesh</em>) — the only occurrence of this specific phrase in the OT, anticipating the NT's 'holy land' terminology.</p>",
        "13": "<p><strong>has kol basar mippenei YHWH ki ne'or mime'on qodsho</strong>: 'Be silent, all flesh, before the LORD, for he has roused himself from his holy dwelling.' The universal call to silence (<em>has</em>, H2013 — the same hush-command as Hab 2:20; Zeph 1:7; Amos 6:10) before YHWH who is stirring from his holy dwelling. The divine rousing (<em>ne'or mime'on qodsho</em>) implies YHWH has been, as it were, inactive — and now he wakes for decisive action. The cosmic silence that precedes divine intervention: all flesh holds its breath before the moment of divine appearance. The NT uses the same silence imagery in Rev 8:1 (silence in heaven for half an hour before the trumpet judgments).</p>"
    },
    "3": {
        "1": "<p><strong>vayar'eni et Yehoshua hakohen hagadol omed lifnei malakh YHWH vehasatan omed al yemino lesitno</strong>: 'Then he showed me Joshua the high priest standing before the angel of the LORD, and Satan standing at his right hand to accuse him.' The fourth vision: the trial of Joshua the high priest. <em>Hasatan</em> (H7854, the adversary, the accuser — with the definite article, indicating a role/title more than a personal name at this stage) stands at the right hand (<em>al yemino</em>) — the position of the prosecuting accuser in a legal proceeding (cf. Ps 109:6). The legal scene is the heavenly court: Joshua represents the restored post-exilic community standing before YHWH, guilty and accused.</p>",
        "2": "<p><strong>vayomer YHWH el hasatan yig'ar YHWH becha hasatan veyig'ar YHWH becha habocher biYerushalayim halo zeh ud mutzal me'esh</strong>: 'And the LORD said to Satan: The LORD rebuke you, O Satan! The LORD who has chosen Jerusalem rebuke you! Is not this a brand plucked from the fire?' YHWH's direct rebuke of the Accuser — the divine intervention that terminates the accusation. The image of Joshua as 'a brand plucked from the fire' (<em>ud mutzal me'esh</em>) is the OT's most vivid picture of rescued sinfulness: a burning stick snatched from the flames just before being consumed. The exile was the fire; the return is the rescue. Jude 23 uses the same image ('save others by snatching them out of the fire') for the gospel's rescue mission.</p>",
        "3": "<p><strong>veYehoshua hayah lavush begadim tzoa'im ve'omed lifnei hamalakh</strong>: 'Now Joshua was standing before the angel, clothed with filthy garments.' <em>Tzoa'im</em> (filthy, H6674 — from <em>tzo'ah</em>, H6674 = excrement, filth) — the strongest word for uncleanness available, the language of human waste. The high priest clothed in excrement represents the post-exilic community's spiritual state: the accumulated guilt of the nation's sin, embodied in its representative before YHWH. The high priestly clothing was meant to represent holiness and purity before YHWH; filthy garments are the exact opposite. This is the human condition before divine grace: standing in one's own defilement before the holy God.</p>",
        "4": "<p><strong>vaya'an vayomer el ha'omedim lefanav leimor haseiru habegadim hatzoa'im me'alav vayomer elav re'eh he'evartiy me'aleycha avonecha vehalbeshu etchem machalatzot</strong>: 'And he said to those who were standing before him: Remove the filthy garments from him. And to him he said: Behold, I have taken your iniquity away from you, and I will clothe you with pure vestments.' The divine removal of the filthy garments is imputed justification in symbolic action: the iniquity (<em>avon</em>, H5771 — guilt, punishment of sin) is removed (<em>he'evartiy</em>, from <em>avar</em> = to pass over, remove, H5674) and pure vestments (<em>machalatzot</em>, H4254 — festal garments, clean apparel) replace them. This is the OT's most direct symbolic portrayal of the transaction that Paul describes in 2 Cor 5:21: God made him to be sin who knew no sin, so that in him we might become the righteousness of God.</p>",
        "5": "<p><strong>vaomar yashimu tzanif tahor al rosho vayashimu hatzanif hatahor al rosho vayalbishuhu begadim</strong>: 'And I said, Let them put a clean turban on his head. So they put a clean turban on his head and clothed him with garments.' Zechariah's active participation in the vision: the prophet requests the clean turban (<em>tzanif tahor</em>, H4701 — the high priestly head covering described in Exod 28:36-37, 39:30-31, inscribed 'Holy to the LORD'). The turban completes the priestly re-clothing. The scene is the OT's most complete picture of full priestly restoration: filthy garments removed, clean clothing given, clean turban placed. Joshua is re-made as high priest — the representative of the restored people before YHWH.</p>",
        "6": "<p><strong>vaya'ad malakh YHWH biYehoshua leimor</strong>: 'And the angel of the LORD solemnly assured Joshua.' The Angel of the LORD (divine figure) now charges Joshua with solemn words — the restored high priest receives his commission. The charge is both promise and condition: if Joshua walks in YHWH's ways and keeps his charge, he will have authority in the temple courts and access among those who stand before the heavenly court.</p>",
        "7": "<p><strong>koh amar YHWH tzvaot im bidrakhai teleikh ve'im et mishmarti tishhmor vegam atta tidin et beiti vegam tishmor et chatzeirai venatati lecha mahlekhim bein ha'omedim haeleh</strong>: 'Thus says the LORD of hosts: If you will walk in my ways and keep my charge, then you shall rule my house and have charge of my courts, and I will give you the right of access among those who are standing here.' The priestly commission's condition: walking in YHWH's ways and keeping his charge. The promised reward: judicial authority in the temple courts (<em>tidin et beiti</em> = you shall judge/rule my house) and access among the heavenly standing ones (<em>ha'omedim</em> = those who stand before YHWH, the angelic council). The high priest, restored and commissioned, is given a place in the heavenly assembly.</p>",
        "8": "<p><strong>shema na Yehoshua hakohen hagadol atta vera'eicha hayoshvim lefaneicha ki anshei mofet hemah ki hineni mevi et avdi Tsemach</strong>: 'Hear now, O Joshua the high priest, you and your friends who sit before you, for they are men who are a sign: for behold, I will bring my servant the Branch.' The messianic announcement: <em>Tsemach</em> (H6780, the Branch — a royal shoot, a new growth from the Davidic tree). Joshua and his colleagues are <em>anshei mofet</em> (men of sign/portent, H4159 — living symbols, omens of what is coming). They are priestly types of the coming <em>Tsemach</em>: YHWH's servant who will be both priest and king (cf. v13, 6:12-13). The Branch is a messianic title used also in Jer 23:5; 33:15; Isa 4:2; Zech 6:12.</p>",
        "9": "<p><strong>ki hineh ha'aven asher natati lifnei Yehoshua al even achat shivah einayim hineni mefatteach pituchhah neum YHWH tzvaot umashti et avon ha'aretz hahi beyom echad</strong>: 'For behold, on the stone that I have set before Joshua, on a single stone with seven eyes, I will engrave its inscription, declares the LORD of hosts, and I will remove the iniquity of this land in a single day.' The stone with seven eyes (<em>even echad shivah einayim</em>) — a single stone engraved by YHWH, with seven eyes (omniscient surveillance), representing either the foundation stone of the temple (the <em>eben shetiyah</em>, the traditional foundation stone) or the person of the Messiah (cf. Isa 28:16; Matt 21:42; 1 Pet 2:6). The removal of iniquity in a single day (<em>beyom echad</em>) is the NT's one-time atonement: the cross as the once-for-all removal of sin (Heb 10:10-14).</p>",
        "10": "<p><strong>bayom hahu neum YHWH tzvaot tiqre'u ish lere'ehu el tachat gefen veal tachat teenah</strong>: 'In that day, declares the LORD of hosts, every one of you will invite his neighbor to come under his vine and under his fig tree.' The eschatological peace formula: sitting under vine and fig tree is the OT's image of agrarian prosperity, security, and covenant blessing (1 Kgs 4:25; Mic 4:4). When iniquity is removed (v9), the community experiences the sabbath rest of covenant harmony: neighbor inviting neighbor, shade provided, prosperity shared. The messianic age that follows the day of atonement is the age of community reconciliation.</p>"
    },
    "4": {
        "1": "<p><strong>vayashov hamalakh haddover bi vaye'ireni kish asher ye'ur mishshenato</strong>: 'And the angel who talked with me came again and woke me, like a man who is awakened out of his sleep.' The fifth vision: the golden lampstand and the two olive trees. Zechariah is awakened from what appears to be a sleep between visions — the transition from one visionary state to another is described as waking. The angel who 'woke him like a man woken from sleep' suggests the depth of the visionary state: prophetic trance, not ordinary wakefulness.</p>",
        "2": "<p><strong>vayomer elai mah atta ro'eh vaomar ra'iti vehineh menorah zahav kulloh ugelah al roshshah veshiv'ah neroteiha aleha shiv'ah veshiv'ah mutzaqot lanerot asher al roshhah</strong>: 'And he said to me, What do you see? I said, I see, and behold, a lampstand all of gold, with a bowl on the top of it, and seven lamps on it, with seven lips on each of the lamps that are on the top of it.' The golden lampstand (<em>menorah zahav</em>) echoes the tabernacle/temple menorah (Exod 25:31-40; 37:17-24) but with additions: the bowl (<em>gulah</em> = basin, H1543) on top serves as a reservoir fed by the two olive trees (v11-12). The seven lamps with seven lips each = forty-nine channels for oil. The elaborate oil-supply system represents the inexhaustibility of divine supply for the light.</p>",
        "3": "<p><strong>ushne zeitim aleha echad mimin hagelah ve'echad al smolah</strong>: 'And there are two olive trees by it, one on the right of the bowl and the other on its left.' The two olive trees (<em>shne zeitim</em>) feed the lampstand with oil without human intervention. They are identified in v14 as 'the two anointed ones' (<em>benei hayitshar</em> = the two sons of fresh oil) who stand beside the Lord of all the earth. The two figures are Zerubbabel (the Davidic prince/civil leader) and Joshua (the high priest) — the two anointed offices of king and priest that will be ultimately united in the messianic priest-king (6:12-13).</p>",
        "4": "<p><strong>va'an veomer el hamalakh haddover bi leimor mah eleh Adonai</strong>: 'And I said to the angel who talked with me, What are these, my lord?' The interpretive dialogue structure: vision → question → interpretation. Zechariah's question opens the theological unpacking of the lampstand vision. The angel's counter-question ('Don't you know what these are?') adds rhetorical emphasis — this is important enough that the prophet should recognize its significance before the explanation is given.</p>",
        "5": "<p><strong>vaya'an hamalakh haddover bi vayomer elai halo yadaa'ta mah eleh vaomar lo Adonai</strong>: 'Then the angel who talked with me answered and said to me, Do you not know what these are? I said, No, my lord.' The prophet's honest acknowledgment of ignorance creates the space for revelation. The visionary dialogue is a Socratic method: the angel's question ('don't you know?') implies the prophet should know — or will know — and the exchange creates the teaching moment. This dialogue structure is characteristic of both Zechariah and Daniel's visions.</p>",
        "6": "<p><strong>vaya'an vayomer elai leimor zeh davar YHWH el Zerubavel leimor lo bechayil velo bekoach ki im beruchi amar YHWH tzvaot</strong>: 'Then he said to me, This is the word of the LORD to Zerubbabel: Not by might, nor by power, but by my Spirit, says the LORD of hosts.' The central theological declaration of the vision. <em>Lo bechayil velo bekoach ki im beruchi</em> — three contrasting terms: <em>chayil</em> (H2428 — military force, army, strength), <em>koach</em> (H3581 — physical power, ability), and <em>ruach</em> (H7307 — Spirit, breath, wind). The temple will not be rebuilt by human military or physical capacity but by the divine Spirit who sustains all legitimate work. This principle is the OT's most concentrated statement of divine-Spirit dependency, applied to Zerubbabel's task of temple rebuilding.</p>",
        "7": "<p><strong>mi atta har hagadol lifnei Zerubavel lemishor vehotzi et ha'aven haroshshah tehshotah tehshotah</strong>: 'Who are you, O great mountain? Before Zerubbabel you shall become a plain. And he shall bring forward the top stone amid shouts of Grace, grace to it!' The 'great mountain' (<em>har hagadol</em>) is the obstacle to temple completion — whether political opposition, resource shortage, or spiritual resistance. YHWH commands it to become a plain (<em>lemishor</em>) before Zerubbabel. The capstone (<em>ha'aven haroshshah</em>, the top stone, the finishing stone of the building) will be brought forward with shouts of <em>chen chen lah</em> (grace, grace to it!) — the community's acclaim when the temple is completed (cf. Ezra 6:15-16).</p>",
        "8": "<p><strong>vayehi davar YHWH elai leimor</strong>: 'Moreover, the word of the LORD came to me, saying.' A second oracle within the vision, confirming Zerubbabel's role. The double oracle (the vision interpretation plus this additional word) underscores the importance of the promise about Zerubbabel and the temple completion.</p>",
        "9": "<p><strong>yedei Zerubavel yisdu habayit hazeh veyedav tevatzzenah veyada'ta ki YHWH tzvaot shelachani aleikhem</strong>: 'The hands of Zerubbabel have laid the foundation of this house; his hands shall also complete it. Then you will know that the LORD of hosts has sent me to you.' The same hands that laid the foundation (520 BCE) will complete the building — a divine guarantee of continuity and completion. The authentication formula ('you will know that YHWH sent me') appears repeatedly in Zechariah's visions: the completion of the temple will vindicate the prophetic word.</p>",
        "10": "<p><strong>ki mi vaz leyom qetannot veshamechu vera'u et ha'eben habedil beyad Zerubavel shiv'ah eleh einei YHWH hemah meshottim bekhol ha'aretz</strong>: 'For whoever has despised the day of small things shall rejoice, and shall see the plumb line in the hand of Zerubbabel. These seven are the eyes of the LORD, which range through the whole earth.' 'The day of small things' (<em>yom qetannot</em>) — the modest, seemingly inadequate beginnings of the second temple. Those who despise the small beginning will yet rejoice when they see completion. The seven eyes (<em>shiv'ah eleh einei YHWH</em>) are YHWH's omniscient surveillance of the whole earth — corresponding to the seven eyes of the stone in 3:9, and the seven lampstand lamps. Seven = completeness of divine knowledge and oversight.</p>",
        "11": "<p><strong>va'an veomer elav mah shene hazeitim ha'eleh al yemim hamenorah veal smolah</strong>: 'Then I said to him, What are these two olive trees on the right and the left of the lampstand?' The question about the two olive trees whose identity has been held back opens the final interpretation of the vision. The two trees that continuously supply oil without human intervention are the key to understanding the vision's theological content.</p>",
        "12": "<p><strong>va'an shenith veomer elav mah shete shibelei hazeitim asher beyad shene tzanterot hazahav hameriiqim me'aleihem hazahav</strong>: 'And a second time I answered and said to him, What are these two branches of the olive trees, which are beside the two golden pipes from which the golden oil is poured out?' Zechariah's precise observation: branches (<em>shibelei</em>, H7641 = ears of grain/branches, figurative for the olive-branch tips) beside golden pipes (<em>tzanterot</em>, H6804 — channels, tubes) through which golden oil flows. The botanical precision of the vision is remarkable: it describes the vascular system of the olive-oil supply. The golden pipes = the channels of divine Spirit-supply.</p>",
        "13": "<p><strong>vayomer elai leimor halo yadaa'ta mah eleh vaomar lo Adonai</strong>: 'He said to me, Do you not know what these are? I said, No, my lord.' The repeated pattern of ignorance acknowledged — the prophet genuinely does not know, and the angel genuinely teaches. The reciprocal exchange emphasizes: the identity of the two anointed ones is not self-evident and requires divine revelation.</p>",
        "14": "<p><strong>vayomer eleh shene venei hayitshar ha'omedim al Adon kol ha'aretz</strong>: 'And he said, These are the two anointed ones who stand by the Lord of the whole earth.' <em>Benei hayitshar</em> (sons of fresh oil, H3323) — lit. sons of oil/new oil, meaning those who are anointed with oil = anointed ones. The two anointed ones = the two office-bearers who supply the divine Spirit to the community: Zerubbabel (civil/royal) and Joshua (priestly). Together they represent the two-office system of the OT covenant community. The ultimate fulfillment: Christ as both king and priest (Heb 7:1-3; Rev 1:6), the one in whom the two offices are permanently united.</p>"
    },
    "5": {
        "1": "<p><strong>vaashuv vaessa et einai vaere vehineh megillah ufah</strong>: 'Again I lifted my eyes and saw, and behold, a flying scroll!' The sixth vision: the flying scroll. <em>Megillah</em> (H4039 — scroll, book roll) + <em>ufah</em> (H5774 — flying) — an enormous scroll flying through the air, twenty cubits long by ten cubits wide. The scroll's dimensions (20 × 10 cubits) are exactly the dimensions of the porch/doorway of Solomon's temple (1 Kgs 6:3), suggesting the scroll is a proclamation emanating from the sanctuary. The flying scroll is a visual theophany of the Torah's curse-provisions activated over the land.</p>",
        "2": "<p><strong>vayomer elai mah atta ro'eh vaomar ani ro'eh megillah ufah orkah esrim be'amah verachbah eser be'amah</strong>: 'And he said to me, What do you see? I answered, I see a flying scroll. Its length is twenty cubits, and its width ten cubits.' The large dimensions (20 × 10 = 200 square cubits) make the scroll visible to all — it is not a private document but a public proclamation. The measurement is given explicitly because the size is significant: this is the most public possible announcement of divine judgment on covenant violators.</p>",
        "3": "<p><strong>vayomer elai zot ha'alah hayotzeit al penei kol ha'aretz ki kol ganav mikkezeh kamo nichah vekhol hanishba sheqer mikkezeh kamo nichah</strong>: 'And he said to me, This is the curse (<em>ha'alah</em>) that goes out over the face of the whole land. For everyone who steals shall be cleaned out according to what is on one side, and everyone who swears falsely shall be cleaned out according to what is on the other side.' The scroll contains two curse-texts: against stealing (<em>ganav</em>) and against false swearing (<em>nishba sheqer</em>) — representative of the Decalogue's commandments against humans (stealing, the eighth) and against God (false oaths using his name, the third). These two represent the two tables of the law: toward neighbor and toward God. The curse-scroll is the covenant's punitive mechanism activated.</p>",
        "4": "<p><strong>hotzetiv neum YHWH tzvaot uvaat el beit haganav veal beit hanishba veshmi sheqer vellanah betokhh beito ukhillathu ve'et etsav ve'et avanav</strong>: 'I will send it out, declares the LORD of hosts, and it shall enter the house of the thief, and the house of him who swears falsely by my name. And it shall remain in his house and consume it, both timber and stones.' The curse enters the covenant-breaker's house and remains (<em>vellanah</em>, to lodge/pass the night) — a persistent presence of judgment that destroys even the physical structure: timber and stones. The image of a self-executing divine curse that physically destroys the violator's house echoes Deut 28:15-68 (covenant curses) and Hab 2:11 (the stone in the wall cries out).</p>",
        "5": "<p><strong>vayetze hamalakh haddover bi vayomer elai sa na et eineicha ure'ah mah hayotzeit hazot</strong>: 'Then the angel who talked with me came forward and said to me, Lift your eyes and see what this is that is going out.' The seventh vision: the woman in the basket (ephah). The shift from the curse-scroll to the container of wickedness continues the theme of sin's judgment and removal from the land.</p>",
        "6": "<p><strong>vaomar mah hi vayomer zot ha'eifah hayotzeit vayomer zot einam bekhol ha'aretz</strong>: 'I said, What is it? And he said, This is the basket that is going out. And he said, This is their iniquity in all the land.' The <em>eifah</em> (H374 — ephah, a standard unit of measurement, about 22 liters) here contains <em>einam</em> (their iniquity, H5771 — the accumulated evil of the land). The ephah-as-wickedness-container is a commercial measure turned into a symbol: the trading and commerce of the land (eiphas were used for measuring grain in trade) has become the vessel of wickedness. The measurement-metaphor implies: sin has been carefully measured out and will be precisely dealt with.</p>",
        "7": "<p><strong>vehineh kikkar oferet nissa uhineh ishah achat yoshevet betokh ha'eifah</strong>: 'And behold, the leaden cover was lifted, and there was a woman sitting in the basket!' A woman (<em>ishah</em>) sitting in the ephah, confined by a lead cover (<em>kikkar oferet</em> — a circular piece of lead). The woman is identified in v8 as Wickedness (<em>harishab</em>, the wicked one). The feminine figure of personified wickedness may reflect the goddess-worship (Asherah, Astarte) that represented one of Israel's most persistent covenant violations. She is contained, covered, and in the process of being transported away from the land.</p>",
        "8": "<p><strong>vayomer zot harishab vayashlech otah el tokh ha'eifah vayashlech et even ha'oferet el piha</strong>: 'And he said, This is Wickedness. And he thrust her back into the basket, and thrust down the leaden weight over its opening.' The angel's forceful action: she tries to get out; he forces her back in and seals the lid. Wickedness personified is contained and controlled — it will not escape from the container in which YHWH has confined it. The sealing of wickedness in the ephah anticipates the binding and sealing of evil in Revelation (Rev 20:2-3: he seized the dragon and bound him for a thousand years).</p>",
        "9": "<p><strong>vaessa et einai vaere vehineh shtei nashim yotz'ot veruach bekanfeihen ulahen kanafayim kekanfei hahasidah vativnah et ha'eifah bein ha'aretz uvein hashamayim</strong>: 'Then I lifted my eyes and saw, and behold, two women coming forward! The wind was in their wings. They had wings like the wings of a stork, and they lifted up the basket between earth and sky.' Two women with stork wings (<em>kekanfei hahasidah</em>) transport the ephah. The <em>hasidah</em> (H2624, stork — from <em>chesed</em>, associated with faithful/loyal birds) has large, powerful wings suitable for long-distance flight. The ephah is lifted between earth and sky — in transit from the land of Israel to its destination.</p>",
        "10": "<p><strong>vaomar el hamalakh haddover bi ana hemah molichot et ha'eifah vayomer elai livnot lah bayit be'eretz Shin'ar vehukhhan venuchah sham al mekhonatah</strong>: 'Then I said to the angel who talked with me, Where are they taking the basket? He said to me, To the land of Shinar, to build a house for it. And when this is prepared, they will set the basket down there on its base.' <em>Eretz Shin'ar</em> (the land of Shinar, H8152 — Genesis's name for Babylonia, Gen 10:10; 11:2) — wickedness is being sent back to Babylon, its spiritual home, where it will have its permanent dwelling (<em>mekhonatah</em> = its base, its established place). The removal of wickedness from the land of Israel to Shinar is the reversal of Ezra 1:7-11: the vessels taken from Jerusalem to Babylon are returned; now wickedness goes the other direction, to Babylon where it belongs. The purification of the land is accomplished by this cosmic removal.</p>",
        "11": "<p><strong>vayomer elai livnot lah bayit be'eretz Shin'ar</strong>: See the previous verse (v10) for the full comment on the Shinar destination. The building of a house for Wickedness in Shinar represents the institutionalization and containment of evil in its appropriate domain — away from the covenant land. The eschatological vision: the holy land purified, wickedness exiled to its proper place.</p>"
    },
    "6": {
        "1": "<p><strong>vaashuv vaessa et einai vaere vehineh arba markavot yotz'ot min bein shene heharim veheharim harim nechoshet</strong>: 'Again I lifted my eyes and saw, and behold, four chariots came out from between two mountains. And the mountains were mountains of bronze.' The eighth and final vision: the four chariots. <em>Arba markavot</em> (four chariots) — the divine war-chariots corresponding to the four patrol riders of the first vision (1:8-11). The two mountains of bronze (<em>harim nechoshet</em>) suggest either the twin mountains flanking Jerusalem (Moriah and the Mount of Olives) or the celestial gateposts of the divine realm, made of incorruptible bronze. The chariots emerge from YHWH's presence to execute his will on the earth.</p>",
        "2": "<p><strong>bamarkavah harishonah susim adumim uvmarkavah hashenit susim shechorim</strong>: 'The first chariot had red horses, the second black horses.' The four chariot-teams: red, black, white, and dappled (vv2-3). The color-associations: red = war/bloodshed; black = famine/death (cf. Rev 6:2-8, the four horsemen of the Apocalypse echo Zechariah's four chariots). The Revelation vision of the four horsemen (Rev 6:1-8) is the NT's most direct development of Zechariah's four-chariot vision.</p>",
        "3": "<p><strong>uvmarkavah hashlishit susim levanim uvmarkavah har'vit susim beruddim amutzim</strong>: 'The third white horses, the fourth chariot dappled horses — all of them powerful.' <em>Beruddim amutzim</em> (dappled, powerful/strong) — the dappled horses sent to the south (v6). The four chariot colors correspond to the four compass directions: north (black), south (dappled), west (white, going after them), east (red, kept to go over the whole earth). YHWH's executive agents cover all four directions of the earth.</p>",
        "4": "<p><strong>va'an veomer el hamalakh haddover bi mah eleh Adonai</strong>: 'Then I answered and said to the angel who talked with me, What are these, my lord?' The standard interpretive question. The angel's response (v5) identifies the chariots as the four winds/spirits of heaven — YHWH's executive agents sent to patrol and act throughout all the earth.</p>",
        "5": "<p><strong>vaya'an hamalakh vayomer elai eleh arba ruchot hashamayim yotz'ot mithatzeiv al Adon kol ha'aretz</strong>: 'And the angel answered and said to me, These are the four winds of heaven, going out after presenting themselves before the Lord of all the earth.' The four winds (<em>arba ruchot hashamayim</em>) = the four spirits/winds of heaven, YHWH's executive agents dispatched from the divine council. They stand before the Lord of the whole earth (<em>Adon kol ha'aretz</em>) before deployment — receiving their commissions at the divine court before going to execute YHWH's purposes in history.</p>",
        "6": "<p><strong>asher bah susim hashchorim yotz'im el eretz tzafon vehalevavim yatze'u el achar'eihem vehaveruddim yatze'u el eretz hateman</strong>: 'The one with the black horses goes toward the north country, the white ones go after them, and the dappled ones go toward the south country.' The deployment: black (north = Babylon/Assyria), white (west/after the black), dappled (south = Egypt). The dominant direction is north — Babylon, the primary object of divine attention in post-exilic prophecy.</p>",
        "7": "<p><strong>vaha'amutzim yatze'u vevakeshu lalechet lehithalek ba'aretz vayomer lekhu hithalku ba'aretz vayithalku ba'aretz</strong>: 'When the powerful horses came out, they were impatient to go and patrol the earth. And he said, Go, patrol the earth. So they patrolled the earth.' The powerful (strong, dappled) horses are eager to go — restless for action. The divine commission is simple: Go, patrol the earth. The response: they go. YHWH's executive agents are obedient, powerful, and comprehensive in their coverage. The frame of the book: first vision (ch1 — patrol returns with report of rest) and final vision (ch6 — patrol commissioned to go) form a bracket around the eight visions.</p>",
        "8": "<p><strong>vayizaq oti vayedabber elai leimor re'eh hayotze'im el eretz tzafon heniichu et ruchi be'eretz tzafon</strong>: 'Then he cried to me, Behold, those who go toward the north country have set my Spirit at rest in the north country.' The black horses going to the north ('quieted' or 'set YHWH's Spirit at rest' in the north) means the divine wrath against Babylon has been satisfied — YHWH's purpose accomplished there. The Babylonian empire was destroyed in 539 BCE (Cyrus); by Zechariah's time (520-518 BCE) YHWH's judgment of Babylon is complete. The first vision (ch1) showed the earth at rest while Jerusalem suffered; this final vision shows YHWH's wrath against the north satisfied, and restoration about to begin.</p>",
        "9": "<p><strong>vayehi davar YHWH elai leimor</strong>: 'The word of the LORD came to me: Receive from the exiles...' This oracle (vv9-15) is the symbolic coronation of Joshua the high priest with a crown, accompanied by the messianic oracle of the Branch (v12-13). The reception of silver and gold from the returning exiles (Heldai, Tobijah, Jedaiah, who had come from Babylon) for making the crown connects the material gifts of the diaspora to the symbolic act of crowning.</p>",
        "10": "<p><strong>qach me'et hagolah me'et Cheldai ume'et Toviyah ume'et Yedayah uba'ta ata bayom hahu uba'ta beit Yoshiyah ben Tzefanyah</strong>: 'Take silver and gold from the exiles — from Heldai, Tobijah, and Jedaiah — who have arrived from Babylon, and go the same day to the house of Josiah, the son of Zephaniah.' The three donors from Babylon bring materials for the crown. Their arrival from exile on this specific day is providential: they become the human instruments of the symbolic act. The house of Josiah son of Zephaniah is the staging point for the crown-making.</p>",
        "11": "<p><strong>velaqachta kesef vezahav ve'asita atarot venasata berosh Yehoshua ben Yehotzadak hakohen hagadol</strong>: 'Take from them silver and gold, and make a crown, and set it on the head of Joshua, the son of Jehozadak, the high priest.' The crowning of Joshua (<em>atarot</em>, H5850 — crown, plural of majesty) on the head of the high priest is a symbolic action. Note: the crown is placed on the head of Joshua the priest, not Zerubbabel the prince — because the oracle (v12-13) is about the Branch, the coming messianic figure, who will be both priest and king. Joshua acts as the symbolic representative/type of the coming priest-king.</p>",
        "12": "<p><strong>ve'amarta elav leimor koh amar YHWH tzvaot leimor hineh ish Tsemach shmo umitachtav yitzmach uvanah et heikhal YHWH</strong>: 'And say to him, Thus says the LORD of hosts: Behold, the man whose name is the Branch — he will branch out from his place and he will build the temple of the LORD.' The messianic announcement of the vision: <em>ish Tsemach shmo</em> (a man whose name is the Branch). <em>Tsemach</em> (H6780 — a shoot, a sprout, a branch) is the primary royal-messianic title in Zechariah (cf. 3:8) and Jeremiah (23:5; 33:15: I will raise up for David a righteous Branch). The wordplay on <em>yitzmach</em> (he will branch/sprout from his place) is intentional: the Branch branches out — his nature is expressed in his name. He will build the temple — in the ultimate sense, Christ is the builder of the spiritual temple (Matt 16:18; Eph 2:20-22).</p>",
        "13": "<p><strong>vehu yivneh et heikhal YHWH vehu yissa hod veyashav umashol al kis'o vehayah kohen al kis'o va'atzat shalom tihyeh bein shenehem</strong>: 'It is he who shall build the temple of the LORD and shall bear royal honor, and shall sit and rule on his throne. And there shall be a priest on his throne, and the counsel of peace shall be between them both.' The single greatest Christological verse in Zechariah: the Branch will be simultaneously king (sit and rule on his throne) and priest (kohen on his throne). The priest-king synthesis — the combining of two offices that were scrupulously separated in the OT (Uzziah was struck with leprosy for attempting it, 2 Chr 26:16-21) — is only possible in the messianic figure. Hebrews 7 identifies Christ as the fulfillment: a priest forever in the order of Melchizedek (who was both king of Salem and priest, Gen 14:18), bearing the glory of both offices in one person.</p>",
        "14": "<p><strong>veha'atarah tihyeh leCheldai uleToviahu uleYedayah veleChen ben Tzefanyah lezikkaron beheikhal YHWH</strong>: 'And the crown shall be in the temple of the LORD as a reminder to Helem, Tobijah, Jedaiah, and Hen the son of Zephaniah.' The crown is deposited in the temple as a memorial (<em>zikkaron</em>, H2146 — a memorial, a reminder, a sign). The crown that was placed on Joshua's head now becomes a permanent symbolic object in the temple, pointing forward to the coming priest-king who will wear the royal and priestly crowns permanently. The memorial function: the symbolic crowning of Joshua points forward to the Messiah's actual enthronement.</p>",
        "15": "<p><strong>urchoqim yavo'u uvanah beheikhal YHWH vidatem ki YHWH tzvaot shelachani aleikhem vehayah im shamo'a tishme'u bekol YHWH Eloheikhem</strong>: 'And those who are far off shall come and help to build the temple of the LORD. And you shall know that the LORD of hosts has sent me to you. And this shall come to pass, if you will diligently obey the voice of the LORD your God.' The expansion: 'those who are far off' (<em>rechogim</em>) — the distant exiles and, by extension, the Gentiles — will come to build the temple. The NT fulfillment: Gentiles incorporated into the spiritual temple (Eph 2:19-22: built together into a dwelling place for God by the Spirit). The closing condition ('if you will diligently obey') maintains the covenant's conditional character even within an eschatological promise.</p>"
    },
    "7": {
        "1": "<p><strong>vayehi bishnat arba leDaryavesh hamelek haya davar YHWH el Zekharyahu bearba'ah lachodesh hateviit bekhislev</strong>: 'In the fourth year of King Darius, the word of the LORD came to Zechariah on the fourth day of the ninth month, which is Chislev.' The date formula (December 518 BCE) — two years after the eight night visions (520-519 BCE) and while the temple construction continues. The occasion is a question from Bethel about the fourth-month and fifth-month fasts that commemorated the siege and destruction of Jerusalem. The question initiates an extended response (chs 7-8) about the meaning of religious observance and the proper heart of covenant religion.</p>",
        "2": "<p><strong>vayishlach Beit El Sar'etzer veRegem Melekh va'anashav lechalot et penei YHWH</strong>: 'Now Bethel had sent Sharezer and Regem-melech and their men to entreat the favor of the LORD.' The delegation from Bethel (<em>Beit El</em> = house of God, ironically: the city associated with Jeroboam's golden calves, 1 Kgs 12:29) comes to inquire of YHWH. The proper response to questions about religious practice is to seek YHWH's will — a positive impulse behind the question that YHWH's response will deepen and redirect.</p>",
        "3": "<p><strong>leimor el hakkohanim asher leVeit YHWH tzvaot ve'el hanevi'im leimor ha'evkeh bachodesh hachameshy hinazer kehasher asiti zeh kammeh shanim</strong>: 'To ask the priests of the house of the LORD of hosts and the prophets, Should I weep and abstain in the fifth month, as I have done for so many years?' The fifth-month fast (<em>tzom hachamishi</em>) commemorated the burning of the temple and destruction of Jerusalem in Ab/Tevet of 586 BCE (2 Kgs 25:8-9; Jer 52:12-13). The question: now that the temple is being rebuilt, is this fast still required? The question is legitimate and practical, but YHWH's response redirects it to a deeper question about the nature of all religious observance.</p>",
        "4": "<p><strong>vayehi davar YHWH tzvaot elai leimor</strong>: 'Then the word of the LORD of hosts came to me.' The prophetic formula introduces YHWH's extended response to the Bethel delegation. Rather than simply answering yes or no about the fast, YHWH uses the question as an occasion for a comprehensive teaching about covenant faithfulness.</p>",
        "5": "<p><strong>emor el kol am ha'aretz ve'el hakkohanim leimor ki tztzmtem vesfod bachameshy uvashvi'i vezeh shiv'im shanah ha'ani tzamtem tzom tzoniy li</strong>: 'Say to all the people of the land and the priests: When you fasted and mourned in the fifth month and in the seventh month, for these seventy years, was it for me that you fasted?' The penetrating question cuts to the motivational core: <em>ha'ani tzamtem tzom tzoniy li</em> (was it really for me that you fasted for me?). The repeated pronoun <em>li</em> (for me) emphasizes the point: fasting done for God vs. fasting done for human emotional release or social obligation. YHWH challenges the assumption that religious observance is automatically done 'for him' — it may in fact be for oneself.</p>",
        "6": "<p><strong>vechekhalachem vashtochem halo atem haokhlim vehem shottim</strong>: 'And when you eat and when you drink, do you not eat for yourselves and drink for yourselves?' The logic is extended: if your eating and drinking is for yourselves, so is your fasting. Both religious observance (fasting) and ordinary life (eating/drinking) are evaluated by the same criterion: is it done unto YHWH or for oneself? The NT form: whether you eat or drink, or whatever you do, do all to the glory of God (1 Cor 10:31). The problem is not fasting per se but fasting disconnected from covenant relationship with YHWH.</p>",
        "7": "<p><strong>halo et haddevarim asher qara YHWH beyadh hanevi'im harishonim bihyot Yerushalayim yoshevet ushleivah ve'areha saviveiha vehanegev veshefelah yoshevet</strong>: 'Were not these the words that the LORD proclaimed by the former prophets, when Jerusalem was inhabited and prosperous, and her cities around her, and the Negeb and the Shephelah were inhabited?' The 'former prophets' again — YHWH's question points back to the pre-exilic prophetic tradition. The same ethical demands were given when Jerusalem was prosperous and populated; their rejection led to the exile. The current community, returning from exile, is asked: will you repeat the fathers' pattern or learn from it?</p>",
        "8": "<p><strong>vayehi davar YHWH el Zekharyahu leimor</strong>: 'And the word of the LORD came to Zechariah, saying.' The formal oracle introduction marks a new element in YHWH's response: the positive content of what covenant faithfulness actually requires. Verses 9-10 contain the three-part ethical summary that is the OT's most concentrated statement of social covenant obligation.</p>",
        "9": "<p><strong>koh amar YHWH tzvaot mishpat emet shafetu vecheced verachamim asu ish et achiv</strong>: 'Thus says the LORD of hosts: Render true judgments, show kindness and mercy to one another.' The three covenant-ethics: (1) <em>mishpat emet</em> (true/faithful justice — righteous judgment in the courts); (2) <em>chesed</em> (H2617 — steadfast covenant love, loyal kindness — in human relationships); (3) <em>rachamim</em> (H7356 — compassion, tender mercy — toward the vulnerable). These are the three dimensions of the OT's social ethic, corresponding to the three levels of human relationship: legal-formal (justice in courts), covenant-communal (loyal love between partners), and compassionate (tender care for the weak). Micah 6:8's do justice, love kindness, and walk humbly with your God is the same three-fold structure.</p>",
        "10": "<p><strong>ve'almanah veyatom ger ve'ani al ta'ashoqu verah ish achiv al tacheshvu bilvavchem</strong>: 'Do not oppress the widow, the fatherless, the sojourner, or the poor, and let none of you devise evil against another in your heart.' The four protected classes — widow, orphan, sojourner, poor — are the most vulnerable members of covenant society, those without natural protectors. Their protection is the litmus test of covenant faithfulness throughout the Mosaic law (Exod 22:21-24; Deut 14:29; 24:17-22) and the prophets (Isa 1:17; Jer 7:6; Amos 5:12; Mal 3:5). The final prohibition — 'let none devise evil in his heart' — addresses the internal disposition before the external act: the heart's intentions, not just the visible behavior, are under covenant obligation.</p>",
        "11": "<p><strong>vayema'anu lehaqshiv vayitenu katef soreref ve'ozneihem hikbidu mishmo'a</strong>: 'But they refused to pay attention and turned a stubborn shoulder and stopped their ears that they might not hear.' The fathers' response to the same prophetic message: refusal and defiance. <em>Katef soreref</em> (H5637 — a stubbornly turned shoulder) is the image of an ox or donkey that resists the yoke by turning its shoulder away. The stopping of ears (<em>hikbidu mishmo'a</em> = they made their ears heavy/dull from hearing) is the same hardening that Isaiah describes (Isa 6:10: make their ears heavy and their eyes shut). The physical metaphors for spiritual resistance are vivid: not passive ignorance but active refusal.</p>",
        "12": "<p><strong>velibam samu shamir mishmo'a et haTorah ve'et hadevarim asher shalach YHWH tzvaot berucham el yad hanevi'im harishonim vayehi qetzef gadol me'et YHWH tzvaot</strong>: 'They made their hearts diamond-hard lest they should hear the law and the words that the LORD of hosts had sent by his Spirit through the former prophets. Therefore great anger came from the LORD of hosts.' <em>Lev shamir</em> (a heart of diamond/flint, H8068 — the hardest known stone in the ancient world, used for engraving) — the ultimate hardening of the heart against YHWH's word. The <em>shamir</em> stone is so hard it can cut other stones; used metaphorically for a heart that repels all impression from YHWH's word. The great anger (<em>qetzef gadol</em>) that resulted was the exile: YHWH's word sent through the prophets, refused, led to the covenant curse.</p>",
        "13": "<p><strong>vayehi ka'asher qara velo shame'u ken yiqre'u velo eshmea amar YHWH tzvaot</strong>: 'As I called, and they would not hear, so they called, and I would not hear, says the LORD of hosts.' The talio principle of divine-human reciprocity: they did not hear my call → I will not hear their call. The symmetry is judicial: the same deafness they applied to YHWH's prophets, YHWH applies to their prayers in crisis. This is the prophetic warning pattern: Prov 1:24-28 uses the same structure (I called and you refused ... then you will call and I will not answer). The exile was the actualization of this reciprocal deafness.</p>",
        "14": "<p><strong>va'esa'rem al kol hagoyim asher lo yeda'um veha'aretz neshammah achareihem me'over ume'ashev vayasimu eretz chemdah lishemamah</strong>: 'And I scattered them with a whirlwind among all the nations that they had not known. Thus the land they left was desolate, so that no one went to and fro, and the pleasant land was made desolate.' YHWH scattered them (<em>asa'rem bise'arah</em> = with a storm-wind/whirlwind I scattered them) among nations they had not known. The pleasant land (<em>eretz chemdah</em>, H2532 — the desirable, beautiful land of Canaan) was made desolate: the land that was gift became emptied of its people. The historical reality of 586-539 BCE is the theological application of vv11-13's analysis of covenant hardening. The chapter ends with desolation — setting up ch8's mirror reversal with restoration promises.</p>"
    }
}


def main():
    c = load_comm('mkt-original', 'zechariah')
    merge_comm(c, DATA)
    save_comm('mkt-original', 'zechariah', c)
    total = sum(len(v) for v in DATA.values())
    print(f'zechariah mkt-original: added up to {total} verses across ch1-7')


if __name__ == '__main__':
    main()
